  ('disabled-0a2fc18c-moex-00091', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-113-6948958a', 'sub-disabled-0a2fc18c-07', NULL, 'single_choice', '在短期的完全競爭市場中，當個別廠商達到利潤極大化的產量時，下列敘 述何者正確？', '["該產量位於邊際成本線的最低點", "該產量位於平均成本線的最低點", "該產量位於邊際成本線和平均成本線的交點", "該產量位於邊際成本線和市場價格線的交點"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:25+00:00", "source_pdf_sha1": "85be7467d750", "answer_pdf_sha1": "6fb4e390116a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "408", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL),
